uv run python -c "
import pathlib
src = pathlib.Path('src/minivess/pipeline/loss_functions.py').read_text(encoding='utf-8')
# Search for the GraphTopologyLoss accumulator initialization
lines = src.split('\n')
for i, line in enumerate(lines):
    if 'torch.tensor(0.0' in line and i > 500:
        print(f'Line {i+1}: {line.strip()}')
        if 'float32' in line:
            print('  -> Uses float32: GOOD')
        elif 'logits.dtype' in line:
            print('  -> Uses logits.dtype: BAD (FP16 overflow risk)')
        else:
            print('  -> Defaults to float32 (no explicit dtype): ACCEPTABLE')
"

uv run python -c "
import pathlib

root = pathlib.Path('.')
active_extensions = {'.py', '.yaml', '.yml', '.toml', '.env', '.sh'}
exclude_dirs = {'v0-2_archive', 'metalearning', 'docs/planning', '.git', '__pycache__', 'node_modules', '.claude/metalearning'}

hits = []
for p in root.rglob('*'):
    if not p.is_file():
        continue
    if p.suffix not in active_extensions:
        continue
    # Skip archive/docs/metalearning
    parts_str = str(p)
    if any(ex in parts_str for ex in exclude_dirs):
        continue
    try:
        content = p.read_text(encoding='utf-8')
    except (UnicodeDecodeError, PermissionError):
        continue
    if 'europe-north1' in content:
        lines = [f'  L{i+1}: {l.strip()}' for i, l in enumerate(content.split('\n'))
                 if 'europe-north1' in l and not l.strip().startswith('#')]
        if lines:  # Only non-comment references
            hits.append((str(p), lines))

if hits:
    print(f'WARNING: {len(hits)} active files still reference europe-north1:')
    for path, lines in hits:
        print(f'  {path}:')
        for l in lines[:3]:
            print(f'    {l}')
else:
    print('PASS: No active files reference europe-north1 (excluding comments)')
"
